-- ----------------------------------------------------------------------------
-- vw_loops: Table: Loops — build history and forward plan. Each row documents what new concept is introduced, what was witnessed, and what the next empirical question is.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_loops CASCADE;
CREATE VIEW vw_loops WITH (security_invoker = ON) AS
SELECT
  t.loop_id,                                                                    -- Unique identifier: loop-01, loop-02, …
  calc_loops_name(t.loop_id) AS name,                                           -- Display label.
  t.title,                                                                      -- Short title for what this loop adds.
  t.status,                                                                     -- planned | in-progress | complete
  t.new_concept,                                                                -- The new first-class domain concept introduced this loop.
  t.domain_question,                                                            -- The natural-language question this loop's concept answers.
  t.mock_data_note,                                                             -- What the seed data is designed to show.
  t.next_suggestion,                                                            -- Suggestion for the next loop.
  t.commit_hash,                                                                -- Git SHA where this loop first landed.
  t.commit_date                                                                 -- ISO date of the commit.
FROM loops t;

-- ----------------------------------------------------------------------------
-- vw_physics_constants: Table: PhysicsConstants — fundamental constants used in Coulomb's Law calculations. Single source of truth for k, e, a₀, etc.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_physics_constants CASCADE;
CREATE VIEW vw_physics_constants WITH (security_invoker = ON) AS
SELECT
  t.constant_id,                                                                -- Unique identifier (e.g. coulomb_k, elem_charge)
  t.name,                                                                       -- Human-readable name
  t.symbol,                                                                     -- Physics symbol (k, e, a₀, …)
  t.value,                                                                      -- Numeric value in SI units
  t.units,                                                                      -- SI unit string
  t.description                                                                 -- What this constant represents
FROM physics_constants t;

-- ----------------------------------------------------------------------------
-- vw_particles: Table: Particles — named particle archetypes with canonical charge and mass values. Used as reference for Charges rows.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_particles CASCADE;
CREATE VIEW vw_particles WITH (security_invoker = ON) AS
SELECT
  t.particle_id,                                                                -- Unique identifier
  t.name,                                                                       -- Common name (Proton, Electron, …)
  t.canonical_charge,                                                           -- Charge in Coulombs (positive or negative)
  t.canonical_mass,                                                             -- Rest mass in kg
  calc_particles_charge_sign(t.particle_id) AS charge_sign,                     -- positive | negative | neutral
  t.description                                                                 -- Physical description
FROM particles t;

-- ----------------------------------------------------------------------------
-- vw_charges: Table: Charges — individual charged particles with 3D position and physical properties. The raw leaves of the Coulomb's Law DAG.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_charges CASCADE;
CREATE VIEW vw_charges WITH (security_invoker = ON) AS
SELECT
  t.charge_id,                                                                  -- Unique identifier
  t.name,                                                                       -- Human-readable label (Proton A, Electron B, …)
  t.system_id,                                                                  -- FK → Systems.SystemId — which physical system this charge belongs to
  t.particle_id,                                                                -- FK → Particles.ParticleId — archetype (optional)
  t.charge_value,                                                               -- Charge in Coulombs (signed: positive or negative)
  t.position_x,                                                                 -- X coordinate in meters
  t.position_y,                                                                 -- Y coordinate in meters
  t.position_z,                                                                 -- Z coordinate in meters
  t.mass,                                                                       -- Mass in kg (null = massless / not tracked)
  calc_charges_charge_sign(t.charge_id) AS charge_sign,                         -- positive | negative | neutral
  calc_charges_charge_magnitude(t.charge_id) AS charge_magnitude,               -- Absolute value of ChargeValue in Coulombs
  calc_charges_interaction_count(t.charge_id) AS interaction_count              -- Count of ChargeInteractions that reference this charge as Charge1 or Charge2.
FROM charges t;

-- ----------------------------------------------------------------------------
-- vw_systems: Table: Systems — named physical configurations of charges. Groups Charges into testable scenarios (hydrogen atom, NaCl pair, triangle of charges, etc.).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_systems CASCADE;
CREATE VIEW vw_systems WITH (security_invoker = ON) AS
SELECT
  t.system_id,                                                                  -- Unique identifier
  t.name,                                                                       -- Human-readable name
  t.description,                                                                -- What physical situation this represents
  t.is_synthetic,                                                               -- True if this is a constructed example; false if from real measurements
  calc_systems_charge_count(t.system_id) AS charge_count,                       -- Number of charges in this system.
  calc_systems_interaction_count(t.system_id) AS interaction_count,             -- Number of pairwise interactions in this system.
  calc_systems_attractive_count(t.system_id) AS attractive_count,               -- Count of attractive interactions in this system.
  calc_systems_repulsive_count(t.system_id) AS repulsive_count,                 -- Count of repulsive interactions in this system.
  calc_systems_total_charge(t.system_id) AS total_charge,                       -- Algebraic sum of all charges in the system (net charge).
  calc_systems_is_neutral(t.system_id) AS is_neutral,                           -- True when net charge is effectively zero.
  calc_systems_max_force_magnitude(t.system_id) AS max_force_magnitude          -- Strongest pairwise interaction in this system.
FROM systems t;

-- ----------------------------------------------------------------------------
-- vw_charge_interactions: Table: ChargeInteractions — pairwise electrostatic interactions. One row per ordered pair (Charge1, Charge2) within a system. Position and charge values are stored directly (denormalized from Charges) so that DeltaX/Y/Z, DistanceMeters, ForceMagnitude, IsAttractive, and IsRepulsive can be computed as calculated fields. F = k·|q₁·q₂|/r² falls out of the DAG.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_charge_interactions CASCADE;
CREATE VIEW vw_charge_interactions WITH (security_invoker = ON) AS
SELECT
  t.interaction_id,                                                             -- Unique identifier
  calc_charge_interactions_name(t.interaction_id) AS name,                      -- Display label.
  t.system_id,                                                                  -- FK → Systems.SystemId
  t.charge1_id,                                                                 -- FK → Charges.ChargeId (first particle)
  t.charge2_id,                                                                 -- FK → Charges.ChargeId (second particle)
  t.charge1_label,                                                              -- Human label copied from Charges.Name at seed time
  t.charge2_label,                                                              -- Human label copied from Charges.Name at seed time
  t.q1,                                                                         -- Charge value of Charge1 in Coulombs (copied from Charges.ChargeValue)
  t.q2,                                                                         -- Charge value of Charge2 in Coulombs (copied from Charges.ChargeValue)
  t.x1,                                                                         -- X position of Charge1 in meters (copied from Charges.PositionX)
  t.y1,                                                                         -- Y position of Charge1 in meters (copied from Charges.PositionY)
  t.z1,                                                                         -- Z position of Charge1 in meters (copied from Charges.PositionZ)
  t.x2,                                                                         -- X position of Charge2 in meters (copied from Charges.PositionX)
  t.y2,                                                                         -- Y position of Charge2 in meters (copied from Charges.PositionY)
  t.z2,                                                                         -- Z position of Charge2 in meters (copied from Charges.PositionZ)
  t.coulomb_k,                                                                  -- Coulomb's constant: 8.99×10⁹ N·m²·C⁻². Stored per-row so the formula is self-contained.
  calc_charge_interactions_delta_x(t.interaction_id) AS delta_x,                -- X2 − X1: displacement in X from Charge1 to Charge2 in meters.
  calc_charge_interactions_delta_y(t.interaction_id) AS delta_y,                -- Y2 − Y1: displacement in Y from Charge1 to Charge2 in meters.
  calc_charge_interactions_delta_z(t.interaction_id) AS delta_z,                -- Z2 − Z1: displacement in Z from Charge1 to Charge2 in meters.
  calc_charge_interactions_distance_squared(t.interaction_id) AS distance_squared,-- r² = ΔX² + ΔY² + ΔZ² in m². Intermediate value for Coulomb's Law.
  calc_charge_interactions_distance_meters(t.interaction_id) AS distance_meters,-- r = √(r²): charge separation in meters.
  calc_charge_interactions_distance_picometers(t.interaction_id) AS distance_picometers,-- Distance expressed in picometers (r × 10¹²). Human-readable at atomic scale.
  calc_charge_interactions_charge_product(t.interaction_id) AS charge_product,  -- q₁ · q₂ (signed). Positive → same-sign charges (repulsive). Negative → opposite-sign (attractive).
  calc_charge_interactions_force_magnitude(t.interaction_id) AS force_magnitude,-- F = k · |q₁ · q₂| / r² in Newtons. This is Coulomb's Law.
  calc_charge_interactions_is_attractive(t.interaction_id) AS is_attractive,    -- True when charges have opposite signs (ChargeProduct < 0). Force pulls the particles together.
  calc_charge_interactions_is_repulsive(t.interaction_id) AS is_repulsive,      -- True when charges have the same sign (ChargeProduct > 0). Force pushes the particles apart.
  calc_charge_interactions_interaction_type(t.interaction_id) AS interaction_type,-- attractive | repulsive | neutral — derived from sign of ChargeProduct.
  calc_charge_interactions_force_in_atto_newtons(t.interaction_id) AS force_in_atto_newtons-- ForceMagnitude expressed in attonewtons (F × 10¹⁸). Human-readable at atomic scale.
FROM charge_interactions t;

-- ----------------------------------------------------------------------------
-- vw_force_vectors: Table: ForceVectors — unit vector and full Cartesian force components for each ChargeInteraction. FX, FY, FZ decompose the scalar ForceMagnitude along the displacement direction. Force on Charge1 due to Charge2: attractive → pulls C1 toward C2 (−r̂); repulsive → pushes C1 away from C2 (+r̂). Position and interaction values are stored directly (denormalized) so all components compute as pure calculated fields.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_force_vectors CASCADE;
CREATE VIEW vw_force_vectors WITH (security_invoker = ON) AS
SELECT
  t.force_vector_id,                                                            -- Unique identifier (mirrors InteractionId)
  calc_force_vectors_name(t.force_vector_id) AS name,                           -- Display label.
  t.interaction_id,                                                             -- FK → ChargeInteractions.InteractionId
  t.force_magnitude_raw,                                                        -- Scalar force magnitude in Newtons (copied from ChargeInteractions.ForceMagnitude)
  t.dx,                                                                         -- ΔX = X2 − X1 in meters (copied from ChargeInteractions.DeltaX)
  t.dy,                                                                         -- ΔY = Y2 − Y1 in meters (copied from ChargeInteractions.DeltaY)
  t.dz,                                                                         -- ΔZ = Z2 − Z1 in meters (copied from ChargeInteractions.DeltaZ)
  t.dist_raw,                                                                   -- Separation distance r in meters (copied from ChargeInteractions.DistanceMeters)
  t.is_attractive_raw,                                                          -- Attraction flag (copied from ChargeInteractions.IsAttractive)
  calc_force_vectors_unit_x(t.force_vector_id) AS unit_x,                       -- X component of the displacement unit vector r̂ = ΔX/r.
  calc_force_vectors_unit_y(t.force_vector_id) AS unit_y,                       -- Y component of the displacement unit vector ΔY/r.
  calc_force_vectors_unit_z(t.force_vector_id) AS unit_z,                       -- Z component of the displacement unit vector ΔZ/r.
  calc_force_vectors_sign_factor(t.force_vector_id) AS sign_factor,             -- +1 if repulsive (C1 pushed away from C2); −1 if attractive (C1 pulled toward C2).
  calc_force_vectors_fx(t.force_vector_id) AS fx,                               -- X component of force on Charge1 in Newtons. Positive = net force in +X direction.
  calc_force_vectors_fy(t.force_vector_id) AS fy,                               -- Y component of force on Charge1 in Newtons.
  calc_force_vectors_fz(t.force_vector_id) AS fz,                               -- Z component of force on Charge1 in Newtons.
  calc_force_vectors_force_dir_description(t.force_vector_id) AS force_dir_description-- towards (attractive) | away-from (repulsive).
FROM force_vectors t;

-- ----------------------------------------------------------------------------
-- vw_electric_field_points: Table: ElectricFieldPoints — observation points in space at which the electric field contribution of a single source Charge is evaluated. E = k·q/r² pointing away from positive sources. One row per (ObservationPoint, SourceCharge) pair. Source charge and position values stored directly (denormalized) so EX, EY, EZ compute as pure calculated fields.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_electric_field_points CASCADE;
CREATE VIEW vw_electric_field_points WITH (security_invoker = ON) AS
SELECT
  t.field_point_id,                                                             -- Unique identifier
  calc_electric_field_points_name(t.field_point_id) AS name,                    -- Display label.
  t.system_id,                                                                  -- FK → Systems.SystemId
  t.source_charge_id,                                                           -- FK → Charges.ChargeId — the charge creating this field contribution
  t.source_charge_name,                                                         -- Human label of source charge (copied from Charges.Name)
  t.observation_label,                                                          -- Human label for the observation point (midpoint, centroid, etc.)
  t.obs_x,                                                                      -- Observation point X coordinate in meters
  t.obs_y,                                                                      -- Observation point Y coordinate in meters
  t.obs_z,                                                                      -- Observation point Z coordinate in meters
  t.coulomb_k,                                                                  -- Coulomb's constant per-row (8.99×10⁹ N·m²·C⁻²)
  t.source_q,                                                                   -- Charge value of source charge in Coulombs (copied from Charges.ChargeValue)
  t.src_x,                                                                      -- X position of source charge in meters (copied from Charges.PositionX)
  t.src_y,                                                                      -- Y position of source charge in meters (copied from Charges.PositionY)
  t.src_z,                                                                      -- Z position of source charge in meters (copied from Charges.PositionZ)
  calc_electric_field_points_d_x(t.field_point_id) AS d_x,                      -- ObsX − SrcX: displacement from source to observation point.
  calc_electric_field_points_d_y(t.field_point_id) AS d_y,                      -- ObsY − SrcY: displacement in Y.
  calc_electric_field_points_d_z(t.field_point_id) AS d_z,                      -- ObsZ − SrcZ: displacement in Z.
  calc_electric_field_points_distance_squared(t.field_point_id) AS distance_squared,-- r² = dX² + dY² + dZ².
  calc_electric_field_points_distance(t.field_point_id) AS distance,            -- r = √(r²): distance from source charge to observation point.
  calc_electric_field_points_e_field_magnitude(t.field_point_id) AS e_field_magnitude,-- E = k·|q|/r²: electric field strength at observation point due to this source charge in N/C.
  calc_electric_field_points_q_sign(t.field_point_id) AS q_sign,                -- Sign of source charge: +1 for positive, −1 for negative. Field points away from positive, toward negative.
  calc_electric_field_points_ex(t.field_point_id) AS ex,                        -- X component of electric field contribution at observation point (N/C). Positive = points in +X direction.
  calc_electric_field_points_ey(t.field_point_id) AS ey,                        -- Y component of electric field contribution.
  calc_electric_field_points_ez(t.field_point_id) AS ez                         -- Z component of electric field contribution.
FROM electric_field_points t;

-- ----------------------------------------------------------------------------
-- vw_invariant_checks: Table: InvariantChecks — one row per algebraic invariant that the Coulomb's Law DAG must satisfy. These are the model's built-in correctness witnesses.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_invariant_checks CASCADE;
CREATE VIEW vw_invariant_checks WITH (security_invoker = ON) AS
SELECT
  t.invariant_id,                                                               -- Unique identifier
  calc_invariant_checks_name(t.invariant_id) AS name,                           -- Display label.
  t.algebraic_statement,                                                        -- The mathematical identity being checked
  t.natural_language,                                                           -- Plain English: what must be true?
  t.physics_law,                                                                -- Which physics principle this invariant encodes
  t.severity                                                                    -- critical | warning | informational
FROM invariant_checks t;

-- ----------------------------------------------------------------------------
-- vw_system_summary: Table: SystemSummary — one row per system, aggregating all interactions and field points. The model witnesses its own state: total force, dominant pair, net charge, field at midpoints.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_system_summary CASCADE;
CREATE VIEW vw_system_summary WITH (security_invoker = ON) AS
SELECT
  t.summary_id,                                                                 -- Unique identifier (mirrors SystemId)
  calc_system_summary_name(t.summary_id) AS name,                               -- Display label.
  t.system_id,                                                                  -- FK → Systems.SystemId
  calc_system_summary_charge_count(t.summary_id) AS charge_count,               -- Total charges in this system.
  calc_system_summary_interaction_count(t.summary_id) AS interaction_count,     -- Total pairwise interactions.
  calc_system_summary_attractive_count(t.summary_id) AS attractive_count,       -- Count of attractive interactions.
  calc_system_summary_repulsive_count(t.summary_id) AS repulsive_count,         -- Count of repulsive interactions.
  calc_system_summary_total_charge(t.summary_id) AS total_charge,               -- Net algebraic charge across all charges in the system.
  calc_system_summary_is_neutral(t.summary_id) AS is_neutral,                   -- True when |TotalCharge| < 1e-30.
  calc_system_summary_max_force_magnitude(t.summary_id) AS max_force_magnitude, -- Strongest pairwise interaction in Newtons.
  calc_system_summary_min_distance_meters(t.summary_id) AS min_distance_meters, -- Closest pair separation in meters.
  calc_system_summary_all_attractive(t.summary_id) AS all_attractive,           -- True when every interaction in the system is attractive.
  calc_system_summary_all_repulsive(t.summary_id) AS all_repulsive,             -- True when every interaction in the system is repulsive.
  calc_system_summary_has_mixed_interactions(t.summary_id) AS has_mixed_interactions-- True when the system has both attractive and repulsive interactions.
FROM system_summary t;

